module JK_flip_flop (  
    input obf_J,  
    input K,  
    input clk,  
    output reg Q  
);  
    always @(posedge clk) begin  
        if (obf_J && K)  
            Q <= ~Q;  // Toggle  
        else if (obf_J)  
            Q <= 1;   // Set  
        else if (K)  
            Q <= 0;   // Reset  
    end  
endmodule
